8. // UrlToViewModel converts a business-layer ShortenedUrl to a UrlItem viewmodel.
9. func UrlToViewModel(m *bizmodels.ShortenedUrl) *viewmodels.UrlItem {
10. 	return &viewmodels.UrlItem{
11. 		ID:        m.ID,
12. 		Shortcode: m.Shortcode,
13. 		LongUrl:   m.LongUrl,
14. 		ExpiresAt: m.ExpiresAt,
15. 		CreatedAt: m.CreatedAt,
16. 		UpdatedAt: m.UpdatedAt,
17. 	}
18. }
19. 
20. // ListUrlsToResponse builds the paginated list response body from a slice of business models.
21. func ListUrlsToResponse(urls []*bizmodels.ShortenedUrl, total, page, pageSize int) *viewmodels.ListUrlsResponseBody {
22. 	items := make([]*viewmodels.UrlItem, len(urls))
23. 	for i, u := range urls {
24. 		items[i] = UrlToViewModel(u)
25. 	}
26. 	return &viewmodels.ListUrlsResponseBody{
27. 		Items:    items,
28. 		Total:    total,
29. 		Page:     page,
30. 		PageSize: pageSize,
31. 	}
32. }
33. 
34. // CreateUrlToResponse builds a CreateUrlResponseBody from a created ShortenedUrl.
35. // shortUrl is constructed as baseUrl + "/r/" + shortcode.
36. func CreateUrlToResponse(m *bizmodels.ShortenedUrl, baseUrl string) *viewmodels.CreateUrlResponseBody {
37. 	return &viewmodels.CreateUrlResponseBody{
38. 		ID:        m.ID,
39. 		Shortcode: m.Shortcode,
40. 		LongUrl:   m.LongUrl,
41. 		ShortUrl:  baseUrl + "/r/" + m.Shortcode,
42. 		ExpiresAt: m.ExpiresAt,
43. 		CreatedAt: m.CreatedAt,
44. 	}
45. }
46. 
47. // UpdateUrlToResponse builds an UpdateUrlResponseBody from an updated ShortenedUrl.
48. // shortUrl is constructed as baseUrl + "/r/" + shortcode.
49. func UpdateUrlToResponse(m *bizmodels.ShortenedUrl, baseUrl string) *viewmodels.UpdateUrlResponseBody {
50. 	return &viewmodels.UpdateUrlResponseBody{
51. 		ID:        m.ID,
52. 		Shortcode: m.Shortcode,
53. 		LongUrl:   m.LongUrl,
54. 		ShortUrl:  baseUrl + "/r/" + m.Shortcode,
55. 		ExpiresAt: m.ExpiresAt,
56. 		CreatedAt: m.CreatedAt,
57. 		UpdatedAt: m.UpdatedAt,
58. 	}
59. }
