1. import { defineStore } from 'pinia'
2. import { ref } from 'vue'
3. import { DefaultService } from '@/lib/api/services/DefaultService'
4. import type { UrlItem } from '@/lib/api/models/UrlItem'
5. import type { CreateUrlResponseBody } from '@/lib/api/models/CreateUrlResponseBody'
6. import type { UpdateUrlResponseBody } from '@/lib/api/models/UpdateUrlResponseBody'
7. 
8. export interface UrlsState {
9.   items: UrlItem[]
10.   total: number
11.   page: number
12.   pageSize: number
13.   loading: boolean
14.   error: string | null
15. }
16. 
17. export const useUrlsStore = defineStore('urls', () => {
18.   const items = ref<UrlItem[]>([])
19.   const total = ref(0)
20.   const page = ref(1)
21.   const pageSize = ref(0)
22.   const loading = ref(false)
23.   const error = ref<string | null>(null)
24.   const creating = ref(false)
25.   const createError = ref<string | null>(null)
26.   const updating = ref(false)
27.   const updateError = ref<string | null>(null)
28. 
29.   async function fetchUrls(requestedPage = 1, requestedPageSize = 0) {
30.     loading.value = true
31.     error.value = null
32.     try {
33.       const response = await DefaultService.listUserUrls({
34.         page: requestedPage,
35.         pageSize: requestedPageSize > 0 ? requestedPageSize : undefined,
36.       })
37.       if ('status' in response && typeof response.status === 'number') {
38.         // ErrorModel response
39.         error.value = (response as { title?: string }).title ?? 'Failed to load URLs'
40.         return
41.       }
42.       const data = response as { items: UrlItem[] | null; total: number; page: number; page_size: number }
43.       items.value = data.items ?? []
44.       total.value = data.total
45.       page.value = data.page
46.       pageSize.value = data.page_size
47.     } catch (err) {
48.       console.error('fetchUrls: request failed', err)
49.       error.value = 'An unexpected error occurred while loading your URLs.'
50.     } finally {
51.       loading.value = false
52.     }
53.   }
54. 
55.   function reset() {
56.     items.value = []
57.     total.value = 0
58.     page.value = 1
59.     pageSize.value = 0
60.     loading.value = false
61.     error.value = null
62.   }
63. 
64.   async function createUrl(params: {
65.     longUrl: string
66.     shortcode?: string
67.     expiresAt?: string
68.   }): Promise<CreateUrlResponseBody | null> {
69.     creating.value = true
70.     createError.value = null
71.     try {
72.       const response = await DefaultService.createUrl({
73.         requestBody: {
74.           long_url: params.longUrl,
75.           shortcode: params.shortcode,
76.           expires_at: params.expiresAt,
77.         },
78.       })
79.       if ('status' in response && typeof response.status === 'number') {
80.         createError.value = (response as { title?: string }).title ?? 'Failed to create URL'
81.         return null
82.       }
83.       await fetchUrls(1, pageSize.value > 0 ? pageSize.value : undefined)
84.       return response as CreateUrlResponseBody
85.     } catch (err) {
86.       console.error('createUrl: request failed', err)
87.       createError.value = 'An unexpected error occurred while creating your URL.'
88.       return null
89.     } finally {
90.       creating.value = false
91.     }
92.   }
93. 
94.   function clearCreateError() {
95.     createError.value = null
96.   }
97. 
98.   async function updateUrl(params: {
99.     id: number
100.     longUrl: string
101.     shortcode?: string
102.     expiresAt?: string
103.     lastUpdated: string
104.   }): Promise<UpdateUrlResponseBody | null> {
105.     updating.value = true
106.     updateError.value = null
107.     try {
108.       const response = await DefaultService.updateUrl({
109.         id: params.id,
110.         requestBody: {
111.           long_url: params.longUrl,
112.           shortcode: params.shortcode,
113.           expires_at: params.expiresAt,
114.           last_updated: params.lastUpdated,
115.         },
116.       })
117.       if ('status' in response && typeof response.status === 'number') {
118.         const errResponse = response as { status: number; title?: string }
119.         if (errResponse.status === 409) {
120.           updateError.value = 'This item was recently changed by someone else. Please refresh and try again.'
121.           await fetchUrls(page.value, pageSize.value > 0 ? pageSize.value : undefined)
122.         } else {
123.           updateError.value = errResponse.title ?? 'Failed to update URL'
124.         }
125.         return null
126.       }
127.       await fetchUrls(page.value, pageSize.value > 0 ? pageSize.value : undefined)
128.       return response as UpdateUrlResponseBody
129.     } catch (err) {
130.       console.error('updateUrl: request failed', err)
131.       updateError.value = 'An unexpected error occurred while updating your URL.'
132.       return null
133.     } finally {
134.       updating.value = false
135.     }
136.   }
137. 
138.   function clearUpdateError() {
139.     updateError.value = null
140.   }
141. 
142.   return { items, total, page, pageSize, loading, error, creating, createError, updating, updateError, fetchUrls, reset, createUrl, clearCreateError, updateUrl, clearUpdateError }
143. })
144.

